import { defineStore } from "pinia";
import axios from "axios";
import { useSnackbarStore } from "@/stores/snackbar";
import { server } from "@/config";
export const useGoodsStore = defineStore("goods", {
  state: () => ({
    goods: [],
    temp_products: [],
    goods_Query: "",
    barcode_query: "",
    pageCount: 1,
    params: {
      sortBy: [],
      sortDesc: [],
      page: 1,
      itemsPerPage: 1,
    },
    table_loading: false,
    table_temp_product_loading: false,
    add_product_loading: false,
    delete_product_loading: false,
    edit_product_loading: false,
  }),

  actions: {
    async reset_table() {
      this.params.page = 1;
      this.params.sortBy = [];
      this.params.sortDesc = [];
      this.goods_query = "";
      this.pageCount = 1;
      this.table_loading = false;
      this.goods = [];
    },

    async get_goods() {
      const data = this.params;
      this.table_loading = true;

      try {
        const skip = (data.page - 1) * data.itemsPerPage;
        const limit = data.itemsPerPage;

        let query = "";
        if (this.goods_query && this.goods_query.length > 0) {
          query = `&query=${this.goods_query}`;
        }

        const response = await axios.get(
          `${server}/api/get_goods?skip=${skip}&limit=${limit}${query}`
        );

        this.pageCount = response.data.count;
        this.goods = response.data.result;
        this.table_loading = false;

        return response;
      } catch (error) {
        this.table_loading = false;

        const snackbar = useSnackbarStore();

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },

    async get_products_by_barcode() {
      this.table_temp_product_loading = true;
      try {
        let query = "";
        if (this.barcode_query && this.barcode_query.length > 0) {
          query = this.barcode_query;
        }

        const response = await axios.get(
          `${server}/api/get_products_by_barcode?query=${query}`
        );

        response.data.result.forEach((element) => {
          this.temp_products.push(element);
        });

        this.table_temp_product_loading = false;

        return response;
      } catch (error) {
        this.table_temp_product_loading = false;

        const snackbar = useSnackbarStore();

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },

    async add_goods(data) {
      const snackbar = useSnackbarStore();

      this.add_product_loading = true;
      try {
        const response = await axios.post(
          `${server}/api/add_product_dozen`,
          data,
          {
            headers: {
              "Content-Type": "application/json",
            },
            method: "POST",
          }
        );
        this.add_product_loading = false;
        this.goods.push(response.data.result[0]);

        snackbar.showMessage({
         color: "deep-purple-accent-4",
          icon: "clarity:success-standard-solid",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.add_product_loading = false;

        // نحول كائن الأخطاء إلى نصوص
        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },
    async edite_product(data) {
      const snackbar = useSnackbarStore();
      this.edit_product_loading = true;
      try {
        const response = await axios.post(`${server}/api/edit_product`, data, {
          headers: {
            "Content-Type": "application/json",
          },
          method: "post",
        });
        this.edit_product_loading = false;

        // تحديث المنتج في القائمة
        let index = this.goods.findIndex((e) => e.id == data.id_dozen);
        if (index !== -1) {
          this.goods.splice(index, 1, response.data.result[0]);
        }

        this.goods[index] = response.data.result[0];

        snackbar.showMessage({
         color: "deep-purple-accent-4",
          icon: "clarity:success-standard-solid",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.edit_product_loading = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },

    async delete_porduct(data) {
      const snackbar = useSnackbarStore();
      this.delete_product_loading = true;
      try {
        const response = await axios.post(
          `${server}/api/delete_product`,
          data,
          {
            headers: {
              "Content-Type": "application/json",
            },
            method: "post",
          }
        );
        this.delete_product_loading = false;

        // نحذف المنتج من القائمة
        let index = this.goods.findIndex((e) => e.product.id == data.id);
        this.goods.splice(index, 1);

        snackbar.showMessage({
         color: "deep-purple-accent-4",
          icon: "clarity:success-standard-solid",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.delete_product_loading = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },
  },

  getters: {},
});
