<template>
  <v-row justify="center">
    <v-dialog
      :model-value="dialog"
      transition="dialog-bottom-transition"
      fullscreen
    >
      <v-card class="mx-auto card">
        <v-toolbar dark color="#624fc6">
          <v-btn
            icon
            fab
            color="#ffffff"
            x-small
            @click="$emit('popClose')"
            class="mr-1"
          >
            <Icon
              class="icon_download"
              icon="ic:outline-close"
              color="#ffffff"
              width="25"
            />
          </v-btn>

          <v-toolbar-title class="mx-auto d-flex justify-center">
            <h3 style="font-family: 'Cairo', sans-serif">تعديل المنتجات</h3>
          </v-toolbar-title>
        </v-toolbar>

        <v-form ref="edit_goods_form">
          <v-card-text class="mt-2">
            <v-row>
              <v-col cols="12" sm="12" md="12" lg="3">
                <Input
                  v-model="item_info.product.name"
                  @update-value="item_info.product.name = $event"
                  autocomplete="product"
                  type="text"
                  label="اسم المنتج"
                  :rules="NameRulse"
                />
              </v-col>
              <v-col cols="12" sm="12" md="12" lg="3">
                <Selects
                  v-model="type"
                  @update-value="type = $event"
                  label="نوع المنتج"
                  itemValue="value"
                  itemText="type"
                  :items="types"
                  :rules="AllRulse"
                />
              </v-col>

              <v-col cols="12" sm="12" md="12" lg="3">
                <Input
                  v-model="item_info.barcode"
                  @update-value="barcode = $event"
                  type="text"
                  label="باركود المنتج"
                  :rules="NameRulse"
                />
              </v-col>
              <v-col cols="12" sm="12" md="12" lg="3">
                <Input
                  v-model="item_info.model"
                  @update-value="model = $event"
                  type="number"
                  label="الموديل"
                />
              </v-col>
              <v-col cols="12" sm="12" md="12" lg="3">
                <Input
                  v-model="item_info.total_pieces"
                  @update-value="item_info.total_pieces = Number($event)"
                  autocomplete="total_pieces"
                  type="Number"
                  label="عدد القطع الكلي"
                  :rules="AllRulse"
                  :min="1"
                  :max="30"
                />
              </v-col>
              <v-col cols="2" sm="2" md="2" lg="1" class="mt-2">
                <VSwatches v-model="item_info.color" :swatches="swatches" />
              </v-col>
              <v-col cols="12" sm="12" md="12" lg="4">
                <Input
                  v-model="item_info.purchase_price"
                  @update-value="item_info.purchase_price = $event"
                  autocomplete="purchase_price"
                  type="Number"
                  label="سعر الشراء"
                />
              </v-col>
              <v-col cols="12" sm="12" md="12" lg="4">
                <Input
                  v-model="item_info.selling_price"
                  @update-value="item_info.selling_price = $event"
                  autocomplete="selling_price"
                  type="Number"
                  label="سعر البيع"
                  :rules="NameRulse"
                />
              </v-col>

              <v-row v-if="item_info.items && item_info.items.length > 0" dense>
                <template v-for="(item, index) in item_info.items" :key="index">
                  <v-col cols="6" sm="3" md="2" lg="2">
                    <Input
                      v-model="item.size"
                      @update-value="item.size = Number($event)"
                      autocomplete="size"
                      type="text"
                      label="مثلاً S, M المقاس"
                      :rules="SizeRulse"
                    />
                  </v-col>
                  <v-col cols="6" sm="3" md="2" lg="2">
                    <Input
                      v-model="item.quantity"
                      @update-value="item.quantity = Number($event)"
                      autocomplete="label"
                      type="Number"
                      label="عدد القطع"
                      :rules="AllRulse"
                    />
                  </v-col>
                </template>
              </v-row>
            </v-row>
          </v-card-text>
          <v-card-actions class="mt-1">
            <v-btn
              @click="edit_goods"
              :loading="loading"
              color="#624fc6"
              elevation="4"
              variant="flat"
              size="large"
              class="mx-auto border-btn"
            >
              <h4 style="color: white; font-size: 17px">تعديل</h4>
              <template v-slot:loader>
                <span class="custom-loader">
                  <v-icon color="white">mdi-cached</v-icon>
                </span>
              </template>
            </v-btn>
          </v-card-actions>
        </v-form>
      </v-card>
    </v-dialog>
  </v-row>
</template>
<script setup>
import { ref, watch, computed } from "vue";
import Input from "../layout/Input.vue";
import Selects from "../layout/Selects.vue";
import { useGoodsStore } from "@/stores/goods";
const goodsStore = useGoodsStore();
const emit = defineEmits(["popClose"]);
const props = defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
  item: {
    type: Object,
    default: null,
  },
});
const swatches = [
  "#000000",
  "#FFFFFF",
  "#FF0000",
  "#00FF00",
  "#0000FF",
  "#FFFF00",
  "#800080",
  "#00FFFF",
  "#FFC0CB",
  "#FFA500",
  "#808080",
  "#A52A2A",
  "#FFD700",
  "#C0C0C0",
  "#800000",
  "#8B4000",
  "#826644",
];
const edit_goods_form = ref(null);
const type = ref(null);

const types = [
  { name: "type", type: "ملابس", value: 0 },
  { name: "type", type: "احذية", value: 1 },
];

const item_info = ref({});

const NameRulse = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 3 || "الحد الادنى لعدد الاحرف هوه 3",
];

const SizeRulse = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 1 || "الحد الادنى لعدد الاحرف هوه 1",
  (value) => (value || "").length <= 3 || "الحد الاقصى لعدد الاحرف هوه 3",
];

const AllRulse = [(value) => !!value || "هذا الحقل مطلوب"];

const edit_goods = async () => {
  const isValid = await edit_goods_form.value.validate();
  if (isValid.valid) {
    let data = {
      id_product: item_info.value.product.id,
      id_dozen: item_info.value.id,
      name: item_info.value.product.name,
      type: type.value.value,
      barcode: item_info.value.barcode,
      total_pieces: item_info.value.total_pieces,
      color: item_info.value.color,
      purchase_price: item_info.value.purchase_price,
      selling_price: item_info.value.selling_price,
      variants: item_info.value.items,
      model: item_info.value.model,
    };

    try {
      await goodsStore.edite_product(data);
      emit("popClose");
    } catch (e) {
      // error already handled in store
    }
  }
};

const loading = computed(() => goodsStore.edit_product_loading);

watch(
  () => item_info.value.total_pieces,
  (newVal) => {
    if (!Array.isArray(item_info.value.items)) {
      item_info.value.items = [];
    }

    const currentLength = item_info.value.items.length;

    if (newVal > currentLength) {
      const diff = newVal - currentLength;
      for (let i = 0; i < diff; i++) {
        item_info.value.items.push({
          size: "",
          quantity: null,
        });
      }
    }

    if (newVal < currentLength) {
      item_info.value.items.splice(newVal);
    }
  }
);


// عند تغيير العنصر (props.item)
const currentItemId = ref(null);
watch(
  () => props.item,
  (newVal) => {
    if (newVal && typeof newVal === "object") {
      // فقط إذا تغير المعرف id للعنصر، نفذ التهيئة
      if (currentItemId.value !== newVal.id) {
        currentItemId.value = newVal.id;

        item_info.value = {
          ...newVal,
          items: Array.isArray(newVal.items) ? [...newVal.items] : [],
        };

        // تهيئة type أو غيرها حسب الحاجة
        type.value =
          newVal.product.type == 1
            ? { name: "type", type: "احذية", value: 1 }
            : { name: "type", type: "ملابس", value: 0 };
      }
    }
  },
  { immediate: true, deep: true }
);



// Watch the prop deeply and immediately
// watch(
//   () => props.item,
//   (newVal) => {
//     item_info.value = { ...newVal };
//   },
//   { immediate: true, deep: true }
// );
</script>
<style scoped>
.card {
  box-shadow: 0px 0px 0px 0px !important;
}
</style>
